import React, { useMemo } from "react";
import { useAttendeesStore, useLoadingStore } from "@/store";
import { AttendeeServices } from "@/api";
import { ApiGlobalStateManager } from "@/lib/api-state";
import { StatusMessage } from "@/components/StatusMessage";
import { PageCard } from "@/components/PageCard";
import {
    Box,
    Card,
    CardContent,
    Chip,
    LinearProgress,
    Stack,
    Tooltip,
    Typography,
} from "@mui/material";
import GroupIcon from "@mui/icons-material/Group";
import PeopleAltIcon from "@mui/icons-material/PeopleAlt";
import HowToRegIcon from "@mui/icons-material/HowToReg";
import CurrencyRupeeIcon from "@mui/icons-material/CurrencyRupee";
import RestaurantIcon from "@mui/icons-material/Restaurant";
import SchoolIcon from "@mui/icons-material/School";
import CalendarTodayIcon from "@mui/icons-material/CalendarToday";
import { AttendeeBasicInfo } from "@/types/attendee.types";
import { getEventId } from "@/constants/ApiConstants";
import { useSelectedEventContext } from "@/hooks/useSelectedEventContext";
import { CallStatus } from "@/types/api.types";
import { calculateDonationTotal } from '@/utils/eventCalculations';
import { foodColors } from '@/constants/ThemeConstants';

const getFoodColor = (food: string): { bg: string; text: string } => {
    const colorMap: { [key: string]: { bg: string; text: string } } = {
        Veg: { bg: '#e8f5e9', text: '#2e7d32' },
        NonVeg: { bg: '#ffebee', text: '#c62828' },
        Null: foodColors.grey,
    };
    return colorMap[food] || foodColors.orange;
};

interface StatTileProps {
    icon: React.ReactNode;
    label: string;
    primary: React.ReactNode;
    secondary?: React.ReactNode;
    color?: 'primary' | 'success' | 'secondary' | 'info';
}

const StatTile: React.FC<StatTileProps> = ({ icon, label, primary, secondary, color = 'primary' }) => (
    <Card
        variant="outlined"
        sx={{
            borderRadius: 2,
            display: 'flex',
            flexDirection: 'column',
            width: '100%',
            minWidth: 0,
        }}
    >
        <CardContent sx={{ p: 1.5, '&:last-child': { pb: 1.5 } }}>
            <Stack direction="row" spacing={1} sx={{ alignItems: 'center', mb: 0.5 }}>
                <Box sx={{ color: `${color}.main`, display: 'inline-flex' }}>{icon}</Box>
                <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 600, textTransform: 'uppercase', letterSpacing: 0.3 }}>
                    {label}
                </Typography>
            </Stack>
            <Typography variant="h5" sx={{ fontWeight: 700, lineHeight: 1.1, color: `${color}.main` }}>
                {primary}
            </Typography>
            {secondary && (
                <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 0.25 }}>
                    {secondary}
                </Typography>
            )}
        </CardContent>
    </Card>
);

interface SchoolStat {
    schoolName: string;
    totalAttendees: number;
    venueCheckedIn: number;
    totalHeadcount: number;
    checkedInHeadcount: number;
}

export const CheckinStatus: React.FunctionComponent = () => {
    const eventId = getEventId();
    const { selectedEvent } = useSelectedEventContext();
    const { attendeeListState, setAttendeeListState } = useAttendeesStore();
    const { setLoading } = useLoadingStore();
    const hasFetchedRef = React.useRef<boolean>(false);

    React.useEffect(() => {
        if (
            eventId &&
            !hasFetchedRef.current &&
            attendeeListState.status !== CallStatus.Success &&
            attendeeListState.status !== CallStatus.InProgress
        ) {
            hasFetchedRef.current = true;
            ApiGlobalStateManager(AttendeeServices.GetAttendees(eventId), setAttendeeListState);
        }
    }, [eventId, attendeeListState.status]);

    React.useEffect(() => {
        if (attendeeListState.status === CallStatus.InProgress) {
            setLoading(true, 'Loading statistics...');
        } else {
            setLoading(false);
        }
        return () => {
            setLoading(false);
        };
    }, [attendeeListState.status, setLoading]);

    const activeAttendees = useMemo(() => {
        if (!Array.isArray(attendeeListState.data)) return [];
        return attendeeListState.data.filter((a: AttendeeBasicInfo) => (a.headCount ?? 1) > 0);
    }, [attendeeListState.data]);

    const totals = useMemo(() => {
        const registered = activeAttendees.length;
        const totalHeadcount = activeAttendees.reduce((s, a) => s + (a.headCount ?? 1), 0);
        const checkedIn = activeAttendees.filter(a => (a.checkedInAt ?? 0) > 0).length;
        const venueHeadcount = activeAttendees
            .filter(a => (a.checkedInAt ?? 0) > 0)
            .reduce((s, a) => s + (a.headCount ?? 1), 0);
        const donations = activeAttendees.reduce((s, a) => s + calculateDonationTotal(a.donation), 0);
        const checkinPct = registered === 0 ? 0 : Math.round((checkedIn / registered) * 100);
        const headcountPct = totalHeadcount === 0 ? 0 : Math.round((venueHeadcount / totalHeadcount) * 100);
        return { registered, totalHeadcount, checkedIn, venueHeadcount, donations, checkinPct, headcountPct };
    }, [activeAttendees]);

    const foodBreakdown = useMemo(() => {
        // Per food preference: count = # registered attendees, headcount = sum of headcounts,
        // checkedHeadcount = sum of headcounts of those who have checked in.
        type Bucket = { count: number; headcount: number; checkedHeadcount: number };
        const buckets: Record<string, Bucket> = {};
        activeAttendees.forEach(a => {
            const food = a.foodPreference || 'Null';
            const heads = a.headCount ?? 1;
            const isCheckedIn = (a.checkedInAt ?? 0) > 0;
            if (!buckets[food]) buckets[food] = { count: 0, headcount: 0, checkedHeadcount: 0 };
            buckets[food].count += 1;
            buckets[food].headcount += heads;
            if (isCheckedIn) buckets[food].checkedHeadcount += heads;
        });
        const totalHeadcount = Object.values(buckets).reduce((s, b) => s + b.headcount, 0);
        return Object.entries(buckets)
            .sort(([, a], [, b]) => b.headcount - a.headcount)
            .map(([food, b]) => ({
                food,
                count: b.count,
                headcount: b.headcount,
                checkedHeadcount: b.checkedHeadcount,
                pct: totalHeadcount === 0 ? 0 : Math.round((b.headcount / totalHeadcount) * 100),
                checkedPct: b.headcount === 0 ? 0 : Math.round((b.checkedHeadcount / b.headcount) * 100),
                colors: getFoodColor(food),
            }));
    }, [activeAttendees]);

    // Per-day report for the 5 days leading up to (and including) the event start
    // date, plus a final "earlier" bucket aggregating everything registered before
    // that 5-day window. Falls back to "today" as the anchor if the event has no
    // startDateTime.
    const dailyReport = useMemo(() => {
        const days: { label: string; dateLabel: string; iso: string; registered: number; headcount: number; isEventDay: boolean; isAggregate?: boolean }[] = [];
        const anchor = new Date(selectedEvent?.startDateTime ?? Date.now());
        anchor.setHours(0, 0, 0, 0);
        const todayStartMs = (() => {
            const t = new Date();
            t.setHours(0, 0, 0, 0);
            return t.getTime();
        })();

        // Earliest day in the explicit window (= event day - 4).
        const earliestWindowStart = new Date(anchor);
        earliestWindowStart.setDate(anchor.getDate() - 4);
        const earliestWindowStartMs = earliestWindowStart.getTime();

        for (let i = 0; i <= 4; i++) {
            const d = new Date(anchor);
            d.setDate(anchor.getDate() - i);
            const next = new Date(d);
            next.setDate(d.getDate() + 1);
            const startMs = d.getTime();
            const endMs = next.getTime();

            let registered = 0;
            let headcount = 0;
            activeAttendees.forEach(a => {
                if (a.createdAt && a.createdAt >= startMs && a.createdAt < endMs) {
                    registered += 1;
                    headcount += a.headCount ?? 1;
                }
            });

            const isEventDay = i === 0;
            const label = isEventDay
                ? 'Event day'
                : `${i} day${i === 1 ? '' : 's'} before`;
            const dateLabel = d.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' });
            days.push({
                label: startMs === todayStartMs ? `${label} (Today)` : label,
                dateLabel,
                iso: d.toISOString().slice(0, 10),
                registered,
                headcount,
                isEventDay,
            });
        }

        // Final aggregate row for everything registered before the 5-day window.
        let earlierRegistered = 0;
        let earlierHeadcount = 0;
        activeAttendees.forEach(a => {
            if (a.createdAt && a.createdAt < earliestWindowStartMs) {
                earlierRegistered += 1;
                earlierHeadcount += a.headCount ?? 1;
            }
        });
        if (earlierRegistered > 0) {
            days.push({
                label: 'Earlier registrations',
                dateLabel: `Before ${earliestWindowStart.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}`,
                iso: 'earlier',
                registered: earlierRegistered,
                headcount: earlierHeadcount,
                isEventDay: false,
                isAggregate: true,
            });
        }

        const maxValue = days.reduce((m, d) => Math.max(m, d.registered), 0);
        return { days, maxValue };
    }, [activeAttendees, selectedEvent]);

    const checkinStatusBySchool = useMemo<SchoolStat[]>(() => {
        if (activeAttendees.length === 0) return [];
        const schoolGroups: { [key: string]: AttendeeBasicInfo[] } = {};
        activeAttendees.forEach((a) => {
            const school = a.profile?.firstJnvName || 'Unknown';
            if (!schoolGroups[school]) schoolGroups[school] = [];
            schoolGroups[school].push(a);
        });
        const stats: SchoolStat[] = Object.entries(schoolGroups).map(([schoolName, attendees]) => ({
            schoolName,
            totalAttendees: attendees.length,
            venueCheckedIn: attendees.filter(a => a.checkedInAt && a.checkedInAt > 0).length,
            totalHeadcount: attendees.reduce((s, a) => s + (a.headCount ?? 1), 0),
            checkedInHeadcount: attendees
                .filter(a => a.checkedInAt && a.checkedInAt > 0)
                .reduce((s, a) => s + (a.headCount ?? 1), 0),
        }));
        // Sort by checked-in count desc; break ties by larger total attendees, then by name.
        return stats.sort((a, b) => {
            if (b.venueCheckedIn !== a.venueCheckedIn) return b.venueCheckedIn - a.venueCheckedIn;
            if (b.totalAttendees !== a.totalAttendees) return b.totalAttendees - a.totalAttendees;
            return a.schoolName.localeCompare(b.schoolName);
        });
    }, [activeAttendees]);

    if (attendeeListState.status === CallStatus.Failure || attendeeListState.status === CallStatus.BadRequest) {
        return (
            <PageCard>
                <StatusMessage
                    notStartedMessage=""
                    successMessage=""
                    failureMessage="Failed to load attendee data"
                    currentStatus={attendeeListState.status}
                    correlationId={attendeeListState.correlationId}
                />
            </PageCard>
        );
    }

    if (attendeeListState.status !== CallStatus.Success || !Array.isArray(attendeeListState.data)) {
        return null;
    }

    if (activeAttendees.length === 0) {
        return (
            <PageCard>
                <Stack spacing={1.5} sx={{ alignItems: 'center', py: 5 }}>
                    <PeopleAltIcon sx={{ fontSize: 40, color: 'text.disabled' }} />
                    <Typography variant="body2" color="text.secondary">
                        No attendees yet for this event.
                    </Typography>
                </Stack>
            </PageCard>
        );
    }

    return (
        <Stack spacing={2} sx={{ width: '100%' }}>
            {/* Hero check-in progress */}
            <Card variant="outlined" sx={{ borderRadius: 2, width: '100%' }}>
                <CardContent>
                    <Stack direction="row" spacing={1.5} sx={{ alignItems: 'center', mb: 1 }}>
                        <HowToRegIcon color="success" />
                        <Box sx={{ flexGrow: 1, minWidth: 0 }}>
                            <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 600, textTransform: 'uppercase', letterSpacing: 0.3 }}>
                                Venue check-in
                            </Typography>
                            <Typography variant="h5" sx={{ fontWeight: 700, lineHeight: 1.2 }}>
                                {totals.checkedIn}
                                <Typography component="span" variant="body2" color="text.secondary">
                                    {' '}of {totals.registered} registrations
                                </Typography>
                            </Typography>
                        </Box>
                        <Box sx={{ textAlign: 'right' }}>
                            <Typography variant="h4" sx={{ fontWeight: 700, lineHeight: 1, color: 'success.main' }}>
                                {totals.checkinPct}%
                            </Typography>
                            <Typography variant="caption" color="text.secondary">
                                checked in
                            </Typography>
                        </Box>
                    </Stack>
                    <LinearProgress
                        variant="determinate"
                        value={totals.checkinPct}
                        color="success"
                        sx={{ height: 8, borderRadius: 4, bgcolor: 'action.hover' }}
                    />
                    {totals.totalHeadcount !== totals.registered && (
                        <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 1 }}>
                            Headcounts: <strong>{totals.venueHeadcount}</strong> / {totals.totalHeadcount} ({totals.headcountPct}%)
                        </Typography>
                    )}
                </CardContent>
            </Card>

            {/* Stat tiles — responsive grid: 1 col mobile, 3 cols tablet+ */}
            <Box
                sx={{
                    display: 'grid',
                    gap: 1.5,
                    gridTemplateColumns: { xs: '1fr', sm: 'repeat(3, 1fr)' },
                    width: '100%',
                }}
            >
                <StatTile
                    icon={<GroupIcon fontSize="small" />}
                    label="Registered"
                    primary={totals.registered}
                    secondary={totals.totalHeadcount !== totals.registered ? `${totals.totalHeadcount} headcount` : undefined}
                    color="primary"
                />
                <StatTile
                    icon={<HowToRegIcon fontSize="small" />}
                    label="Checked in"
                    primary={totals.checkedIn}
                    secondary={`${totals.venueHeadcount} headcount at venue`}
                    color="success"
                />
                <StatTile
                    icon={<CurrencyRupeeIcon fontSize="small" />}
                    label="Donations"
                    primary={`₹${totals.donations.toLocaleString('en-IN')}`}
                    secondary={`from ${activeAttendees.filter(a => calculateDonationTotal(a.donation) > 0).length} contributors`}
                    color="secondary"
                />
            </Box>

            {/* Food preferences — registered headcount with checked-in headcount overlay */}
            {foodBreakdown.length > 0 && (
                <Card variant="outlined" sx={{ borderRadius: 2, width: '100%' }}>
                    <CardContent>
                        <Stack direction="row" spacing={1.25} sx={{ alignItems: 'center', mb: 1.5 }}>
                            <RestaurantIcon color="primary" fontSize="small" />
                            <Typography variant="subtitle2" sx={{ fontWeight: 600 }}>
                                Food preferences
                            </Typography>
                        </Stack>
                        <Stack spacing={1.25}>
                            {foodBreakdown.map(({ food, headcount, checkedHeadcount, checkedPct, colors }) => (
                                <Box key={food}>
                                    <Stack direction="row" spacing={1} sx={{ alignItems: 'center', mb: 0.25 }}>
                                        <Chip
                                            label={food}
                                            size="small"
                                            sx={{
                                                bgcolor: colors.bg,
                                                color: colors.text,
                                                fontWeight: 600,
                                                height: 20,
                                                fontSize: '0.7rem',
                                            }}
                                        />
                                        <Box sx={{ flexGrow: 1 }} />
                                        <Tooltip title={`${checkedHeadcount} checked-in of ${headcount} registered`}>
                                            <Typography variant="caption" color="text.secondary">
                                                <Box component="span" sx={{ color: 'success.main', fontWeight: 600 }}>{checkedHeadcount}</Box>
                                                {' / '}
                                                <Box component="span" sx={{ fontWeight: 600 }}>{headcount}</Box>
                                                {' ('}{checkedPct}{'%)'}
                                            </Typography>
                                        </Tooltip>
                                    </Stack>
                                    {/* Stacked bar: full width = registered headcount, fill = checked-in. */}
                                    <Box
                                        sx={{
                                            position: 'relative',
                                            height: 8,
                                            borderRadius: 4,
                                            overflow: 'hidden',
                                            bgcolor: colors.bg,
                                            border: '1px solid',
                                            borderColor: 'divider',
                                        }}
                                    >
                                        <Box
                                            sx={{
                                                position: 'absolute',
                                                top: 0,
                                                left: 0,
                                                bottom: 0,
                                                width: `${checkedPct}%`,
                                                bgcolor: colors.text,
                                                transition: 'width 0.3s ease',
                                            }}
                                        />
                                    </Box>
                                </Box>
                            ))}
                        </Stack>
                        <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 1.5 }}>
                            Bar shows checked-in headcount over registered headcount. Numbers count people, not registrations.
                        </Typography>
                    </CardContent>
                </Card>
            )}

            {/* Daily report — 5 days leading up to the event */}
            <Card variant="outlined" sx={{ borderRadius: 2, width: '100%' }}>
                <CardContent>
                    <Stack direction="row" spacing={1.25} sx={{ alignItems: 'center', mb: 1.5 }}>
                        <CalendarTodayIcon color="primary" fontSize="small" />
                        <Box sx={{ flexGrow: 1 }}>
                            <Typography variant="subtitle2" sx={{ fontWeight: 600 }}>
                                Registrations leading to event
                            </Typography>
                            <Typography variant="caption" color="text.secondary">
                                Registrations (and total headcount in brackets) on each of the 5 days before the event
                            </Typography>
                        </Box>
                    </Stack>
                    <Stack spacing={1.25}>
                        {dailyReport.days.map((d) => {
                            const regPct = dailyReport.maxValue === 0 ? 0 : Math.round((d.registered / dailyReport.maxValue) * 100);
                            return (
                                <Box key={d.iso}>
                                    <Stack direction="row" spacing={1} sx={{ alignItems: 'flex-start', mb: 0.5 }}>
                                        <Box sx={{ minWidth: 0, flexGrow: 1 }}>
                                            <Typography
                                                variant="body2"
                                                sx={{
                                                    fontWeight: d.isEventDay ? 700 : 500,
                                                    color: d.isEventDay ? 'primary.main' : 'text.primary',
                                                    lineHeight: 1.2,
                                                }}
                                            >
                                                {d.dateLabel}
                                            </Typography>
                                            <Typography variant="caption" color="text.secondary">
                                                {d.label}
                                            </Typography>
                                        </Box>
                                        <Typography variant="body2" color="text.secondary" sx={{ flexShrink: 0, alignSelf: 'center' }}>
                                            <Box component="span" sx={{ color: 'primary.main', fontWeight: 700 }}>{d.registered}</Box>
                                            {' ('}{d.headcount}{')'}
                                        </Typography>
                                    </Stack>
                                    <Tooltip title={`${d.registered} registrations (${d.headcount} headcount) on ${d.dateLabel}`}>
                                        <LinearProgress
                                            variant="determinate"
                                            value={regPct}
                                            color="primary"
                                            sx={{ height: 6, borderRadius: 3, bgcolor: 'action.hover' }}
                                        />
                                    </Tooltip>
                                </Box>
                            );
                        })}
                    </Stack>
                    <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 1.5 }}>
                        Bars are scaled to the busiest day in this window.
                    </Typography>
                </CardContent>
            </Card>

            {/* By school — stacked rows, mobile-first */}
            <Card variant="outlined" sx={{ borderRadius: 2, width: '100%' }}>
                <CardContent>
                    <Stack direction="row" spacing={1.25} sx={{ alignItems: 'center', mb: 1.5 }}>
                        <SchoolIcon color="primary" fontSize="small" />
                        <Typography variant="subtitle2" sx={{ fontWeight: 600 }}>
                            By school
                        </Typography>
                    </Stack>
                    <Stack spacing={1.5}>
                        {checkinStatusBySchool.map((row) => {
                            const pct = row.totalAttendees === 0 ? 0 : Math.round((row.venueCheckedIn / row.totalAttendees) * 100);
                            const headPct = row.totalHeadcount === 0 ? 0 : Math.round((row.checkedInHeadcount / row.totalHeadcount) * 100);
                            const barColor = pct === 100 ? 'success' : pct >= 50 ? 'primary' : 'warning';
                            return (
                                <Box key={row.schoolName}>
                                    <Stack
                                        direction="row"
                                        spacing={1}
                                        sx={{ alignItems: 'flex-start', mb: 0.5 }}
                                    >
                                        <Box sx={{ flexGrow: 1, minWidth: 0 }}>
                                            <Typography
                                                variant="body2"
                                                sx={{
                                                    fontWeight: 500,
                                                    overflow: 'hidden',
                                                    textOverflow: 'ellipsis',
                                                    whiteSpace: 'nowrap',
                                                }}
                                            >
                                                {row.schoolName}
                                            </Typography>
                                            <Typography variant="caption" color="text.secondary">
                                                {row.venueCheckedIn}/{row.totalAttendees} attendees
                                                {' · '}
                                                {row.checkedInHeadcount}/{row.totalHeadcount} headcount
                                            </Typography>
                                        </Box>
                                        <Box sx={{ textAlign: 'right', flexShrink: 0 }}>
                                            <Typography variant="body2" sx={{ fontWeight: 700, lineHeight: 1.1, color: `${barColor}.main` }}>
                                                {pct}%
                                            </Typography>
                                            <Typography variant="caption" color="text.secondary">
                                                {headPct}% by head
                                            </Typography>
                                        </Box>
                                    </Stack>
                                    <Tooltip title={`${row.venueCheckedIn} of ${row.totalAttendees} checked in`}>
                                        <LinearProgress
                                            variant="determinate"
                                            value={pct}
                                            color={barColor}
                                            sx={{ height: 6, borderRadius: 3, bgcolor: 'action.hover' }}
                                        />
                                    </Tooltip>
                                </Box>
                            );
                        })}
                    </Stack>
                </CardContent>
            </Card>
        </Stack>
    );
};
